use std::collections::BTreeSet;

fn solve(s: String, order: Vec<i64>, k: i64) -> i64 {
    let n = s.len() as i64;
    let total_substrings = n * (n + 1) / 2;
    if k > total_substrings {
        return -1;
    }

    let mut set = BTreeSet::new();
    set.insert(-1);
    set.insert(n);

    let mut total_invalid = total_substrings;

    for (t, &p) in order.iter().enumerate() {
        let left = *set.range(..=p).next_back().unwrap();
        let right = *set.range(p..).next().unwrap();

        let gap_len = right - left - 1;
        total_invalid -= gap_len * (gap_len + 1) / 2;

        let left_gap_len = p - left - 1;
        let right_gap_len = right - p - 1;
        total_invalid += left_gap_len * (left_gap_len + 1) / 2;
        total_invalid += right_gap_len * (right_gap_len + 1) / 2;

        if total_substrings - total_invalid >= k {
            return t as i64;
        }

        set.insert(p);
    }

    -1
}
